"use client";

import React, { useState } from "react";
import { Send, Menu, Plus, Settings, MessageSquare, Bot, FileText, Search } from "lucide-react";

export default function ChatLayout() {
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [messages, setMessages] = useState([
    {
      id: 1,
      role: "assistant",
      content: "Hello, Tarik. I am your Enterprise AI Assistant. How can I help you today?",
      timestamp: new Date().toLocaleTimeString(),
    },
  ]);
  const [input, setInput] = useState("");

  const handleSend = () => {
    if (!input.trim()) return;
    
    // Add user message
    const userMsg = {
      id: Date.now(),
      role: "user",
      content: input,
      timestamp: new Date().toLocaleTimeString(),
    };
    
    setMessages((prev) => [...prev, userMsg]);
    setInput("");

    // Simulate AI response for now (to be replaced with API call)
    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          id: Date.now() + 1,
          role: "assistant",
          content: "I'm currently processing your request via the GPT-Researcher engine...",
          timestamp: new Date().toLocaleTimeString(),
        },
      ]);
    }, 1000);
  };

  return (
    <div className="flex h-screen w-full overflow-hidden font-sans">
      
      {/* Sidebar */}
      <aside 
        className={`${isSidebarOpen ? "w-72 translate-x-0" : "w-0 -translate-x-full"} 
        transition-all duration-300 ease-in-out glass-panel flex flex-col border-r border-white/10 z-20 shrink-0`}
      >
        <div className="p-4 flex items-center justify-between border-b border-white/5">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-cyan-400 flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Bot size={18} className="text-white" />
            </div>
            <span className="font-semibold text-lg text-gradient">Tarik AI</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors lg:hidden">
            <Menu size={18} />
          </button>
        </div>

        <div className="p-4">
          <button className="w-full flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white p-3 rounded-xl transition-all shadow-lg shadow-indigo-500/20 active:scale-95 font-medium">
            <Plus size={18} />
            New Chat
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-1">
          <div className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3 px-2">Recent</div>
          {[1, 2, 3].map((i) => (
            <button key={i} className="w-full flex items-center gap-3 text-left p-2.5 rounded-lg hover:bg-white/5 text-slate-300 hover:text-white transition-colors group">
              <MessageSquare size={16} className="text-slate-500 group-hover:text-indigo-400 transition-colors" />
              <span className="truncate text-sm">Enterprise Architecture Plan</span>
            </button>
          ))}
        </div>

        <div className="p-4 border-t border-white/5 space-y-1">
          <button className="w-full flex items-center gap-3 p-2.5 rounded-lg hover:bg-white/5 text-slate-300 hover:text-white transition-colors">
            <Settings size={18} />
            <span className="text-sm">Settings</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full relative z-10">
        
        {/* Header */}
        <header className="h-16 glass flex items-center justify-between px-4 sm:px-6 sticky top-0 z-30">
          <div className="flex items-center gap-3">
            {!isSidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors">
                <Menu size={20} />
              </button>
            )}
            <h1 className="font-medium text-slate-200">GPT-Researcher Engine</h1>
          </div>
          <div className="flex items-center gap-2">
             <button className="p-2 text-slate-400 hover:text-white hover:bg-white/10 rounded-full transition-colors">
                <Search size={18} />
             </button>
          </div>
        </header>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-6 pb-32">
          <div className="max-w-4xl mx-auto space-y-6">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex gap-4 ${msg.role === "user" ? "flex-row-reverse" : ""}`}>
                <div className={`w-8 h-8 shrink-0 rounded-full flex items-center justify-center shadow-lg ${msg.role === "user" ? "bg-slate-700" : "bg-gradient-to-tr from-indigo-500 to-cyan-400"}`}>
                  {msg.role === "user" ? <span className="text-sm">T</span> : <Bot size={16} className="text-white" />}
                </div>
                <div className={`group flex flex-col gap-1 max-w-[80%] ${msg.role === "user" ? "items-end" : "items-start"}`}>
                  <div className={`px-5 py-3.5 rounded-2xl text-sm leading-relaxed ${
                    msg.role === "user" 
                      ? "bg-indigo-600 text-white rounded-tr-sm shadow-md shadow-indigo-500/10" 
                      : "glass text-slate-200 rounded-tl-sm"
                  }`}>
                    {msg.content}
                  </div>
                  <span className="text-xs text-slate-500 px-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    {msg.timestamp}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Input Area */}
        <div className="absolute bottom-0 left-0 right-0 p-4 sm:p-6 bg-gradient-to-t from-background via-background to-transparent z-30">
          <div className="max-w-4xl mx-auto">
            <div className="glass rounded-2xl p-2 pl-4 flex items-end gap-2 focus-within:ring-1 focus-within:ring-indigo-500/50 transition-shadow">
              <button className="p-2 text-slate-400 hover:text-white transition-colors shrink-0 mb-1">
                <FileText size={20} />
              </button>
              
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Ask Tarik AI anything..."
                className="w-full max-h-32 bg-transparent border-none focus:ring-0 resize-none text-slate-200 py-3 placeholder:text-slate-500 text-sm"
                rows={1}
                style={{ minHeight: '44px' }}
              />
              
              <button 
                onClick={handleSend}
                disabled={!input.trim()}
                className="p-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-500 text-white rounded-xl transition-all shadow-md shrink-0 mb-0.5"
              >
                <Send size={18} />
              </button>
            </div>
            <div className="text-center mt-3 text-[10px] text-slate-500">
              AI can make mistakes. Consider verifying critical information.
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
